sp_widget.client_script:
/* jshint -W025 */
function($scope, $window) {
  var c = this;
  c.data.loading = false;
  c.data.errorMessage = "";

  c.init = function() {
    c.username = "";
    c.password = "";
    c.data.errorMessage = "";
  };

  c.login = function() {
    if (!c.username || !c.password) {
      c.data.errorMessage = "Please enter both username and password.";
      return;
    }

    c.data.loading = true;
    c.data.errorMessage = "";
    c.data.username = c.username;
    c.data.password = c.password;
    c.data.action = "login";

    c.server.update().then(function(response) {
      c.data.loading = false;
      if (response && response.success) {
        // Let the system naturally bring them to the home page route
        $window.location.href = '/sp';
      } else {
        c.data.errorMessage = response.feedback || "Invalid login credentials.";
        c.password = "";
      }
    }).catch(function(error) {
      c.data.loading = false;
      c.data.errorMessage = "A connection error occurred. Please try again.";
    });
  };

  c.init();
}

sp_widget.script:
(function() {
  if (!input) {
    data.success = false;
    return;
  }

  if (input && input.action === "login") {
    var username = input.username;
    var password = input.password;

    try {
      var isUserValid = GlideSession.get().login(username, password);
      if (isUserValid) {
        data.success = true; 
        data.feedback = "Success";
      } else {
        data.success = false;
        data.feedback = "The username or password you entered is incorrect.";
      }
    } catch(e) {
      var authCheck = new global.GlideAuthenticate();
      if (authCheck.loginWithLoginPage(username, password)) {
        data.success = true; 
        data.feedback = "Success";
      } else {
        data.success = false;
        data.feedback = "Authentication failed. Please verify your credentials.";
      }
    }
  }
})();
